INSERT INTO `blocks` (`block_id`, `block_title`, `block_content`, `block_enable`, `datetime`, `username`) VALUES
(1, 'Header Logo', '<p><a href=\\\"/\\\"><img src=\\\"/media/seiten/default/logo.png\\\"></a></p>', 1, '2026-04-07 11:24:51', 'Install'),
(3, 'Footer-Block (rechts)', '<div align=\\\"right\\\">\\r\n    <a href=\\\"/datenschutz\\\">Datenschutz</a><span class=\\\"dot-spacer\\\">•</span><a href=\\\"/impressum\\\">Impressum</a><span class=\\\"dot-spacer\\\">•</span><a href=\\\"/kontakt\\\">Kontakt</a>\\r\n</div>', 1, '2026-04-07 15:36:32', 'Install'),
(7, 'Disclaimer', '<span style=\\\"font-size: 26px;\\\"><b>Datenschutzerklärung</b></span><br>\\r\n<br>\\r\nStand: <u>11. September 2024</u><br>\\r\n<br>\\r\nDie nachfolgende Übersicht fasst die Arten der verarbeiteten Daten und die Zwecke ihrer Verarbeitung zusammen und verweist auf die betroffenen Personen.<br>\\r\n<b>Arten der verarbeiteten Daten</b>\\r\n<ul>\\r\n    <li>Bestandsdaten.</li>\\r\n    <li>Zahlungsdaten.</li>\\r\n    <li>Kontaktdaten.</li>\\r\n    <li>Inhaltsdaten.</li>\\r\n    <li>Vertragsdaten.</li>\\r\n    <li>Nutzungsdaten.</li>\\r\n    <li>Meta-, Kommunikations- und Verfahrensdaten.</li>\\r\n    <li>Protokolldaten.</li>\\r\n</ul>\\r\n<b>Kategorien betroffener Personen</b>\\r\n<ul>\\r\n    <li>Leistungsempfänger und Auftraggeber.</li>\\r\n    <li>Interessenten.</li>\\r\n    <li>Kommunikationspartner.</li>\\r\n    <li>Nutzer.</li>\\r\n    <li>Geschäfts- und Vertragspartner.</li>\\r\n</ul>\\r\n<b>Zwecke der Verarbeitung</b>\\r\n<ul>\\r\n    <li>Erbringung vertraglicher Leistungen und Erfüllung vertraglicher Pflichten.</li>\\r\n    <li>Kommunikation.</li>\\r\n    <li>Sicherheitsmaßnahmen.</li>\\r\n    <li>Büro- und Organisationsverfahren.</li>\\r\n    <li>Organisations- und Verwaltungsverfahren.</li>\\r\n    <li>Feedback.</li>\\r\n    <li>Bereitstellung unseres Onlineangebotes und Nutzerfreundlichkeit.</li>\\r\n    <li>Informationstechnische Infrastruktur.</li>\\r\n    <li>Geschäftsprozesse und betriebswirtschaftliche Verfahren.</li>\\r\n</ul>\\r\n<b>Maßgebliche Rechtsgrundlagen</b><br>\\r\n<br>\\r\nMaßgebliche Rechtsgrundlagen nach der DSGVO: Im Folgenden erhalten Sie eine Übersicht der Rechtsgrundlagen der DSGVO, auf deren Basis wir personenbezogene Daten verarbeiten. Bitte nehmen Sie zur Kenntnis, dass neben den Regelungen der DSGVO nationale Datenschutzvorgaben in Ihrem bzw. unserem Wohn- oder Sitzland gelten können. Sollten ferner im Einzelfall speziellere Rechtsgrundlagen maßgeblich sein, teilen wir Ihnen diese in der Datenschutzerklärung mit.\\r\n<ul>\\r\n    <li>Vertragserfüllung und vorvertragliche Anfragen (Art. 6 Abs. 1 S. 1 lit. b) DSGVO) - Die Verarbeitung ist für die Erfüllung eines Vertrags, dessen Vertragspartei die betroffene Person ist, oder zur Durchführung vorvertraglicher Maßnahmen erforderlich, die auf Anfrage der betroffenen Person erfolgen.</li>\\r\n    <li>Rechtliche Verpflichtung (Art. 6 Abs. 1 S. 1 lit. c) DSGVO) - Die Verarbeitung ist zur Erfüllung einer rechtlichen Verpflichtung erforderlich, der der Verantwortliche unterliegt.</li>\\r\n    <li>Berechtigte Interessen (Art. 6 Abs. 1 S. 1 lit. f) DSGVO) - die Verarbeitung ist zur Wahrung der berechtigten Interessen des Verantwortlichen oder eines Dritten notwendig, vorausgesetzt, dass die Interessen, Grundrechte und Grundfreiheiten der betroffenen Person, die den Schutz personenbezogener Daten verlangen, nicht überwiegen.</li>\\r\n</ul>\\r\nNationale Datenschutzregelungen in Deutschland: Zusätzlich zu den Datenschutzregelungen der DSGVO gelten nationale Regelungen zum Datenschutz in Deutschland. Hierzu gehört insbesondere das Gesetz zum Schutz vor Missbrauch personenbezogener Daten bei der Datenverarbeitung (Bundesdatenschutzgesetz – BDSG). Das BDSG enthält insbesondere Spezialregelungen zum Recht auf Auskunft, zum Recht auf Löschung, zum Widerspruchsrecht, zur Verarbeitung besonderer Kategorien personenbezogener Daten, zur Verarbeitung für andere Zwecke und zur Übermittlung sowie automatisierten Entscheidungsfindung im Einzelfall einschließlich Profiling. Ferner können Landesdatenschutzgesetze der einzelnen Bundesländer zur Anwendung gelangen.<br>\\r\n<br>\\r\nHinweis auf Geltung DSGVO und Schweizer DSG: Diese Datenschutzhinweise dienen sowohl der Informationserteilung nach dem Schweizer DSG als auch nach der Datenschutzgrundverordnung (DSGVO). Aus diesem Grund bitten wir Sie zu beachten, dass aufgrund der breiteren räumlichen Anwendung und Verständlichkeit die Begriffe der DSGVO verwendet werden. Insbesondere statt der im Schweizer DSG verwendeten Begriffe „Bearbeitung\\\" von „Personendaten\\\", \\\"überwiegendes Interesse\\\" und \\\"besonders schützenswerte Personendaten\\\" werden die in der DSGVO verwendeten Begriffe „Verarbeitung\\\" von „personenbezogenen Daten\\\" sowie \\\"berechtigtes Interesse\\\" und \\\"besondere Kategorien von Daten\\\" verwendet. Die gesetzliche Bedeutung der Begriffe wird jedoch im Rahmen der Geltung des Schweizer DSG weiterhin nach dem Schweizer DSG bestimmt.<br>\\r\n<br>\\r\n<b>Geschäftliche Leistungen</b><br>\\r\n<br>\\r\nWir verarbeiten Daten unserer Vertrags- und Geschäftspartner, z. B. Kunden und Interessenten (zusammenfassend als „Vertragspartner\\\" bezeichnet), im Rahmen von vertraglichen und vergleichbaren Rechtsverhältnissen sowie damit verbundenen Maßnahmen und im Hinblick auf die Kommunikation mit den Vertragspartnern (oder vorvertraglich), etwa zur Beantwortung von Anfragen.<br>\\r\n<br>\\r\nWir verwenden diese Daten, um unsere vertraglichen Verpflichtungen zu erfüllen. Dazu gehören insbesondere die Pflichten zur Erbringung der vereinbarten Leistungen, etwaige Aktualisierungspflichten und Abhilfe bei Gewährleistungs- und sonstigen Leistungsstörungen. Darüber hinaus verwenden wir die Daten zur Wahrung unserer Rechte und zum Zwecke der mit diesen Pflichten verbundenen Verwaltungsaufgaben sowie der Unternehmensorganisation. Zudem verarbeiten wir die Daten auf Grundlage unserer berechtigten Interessen sowohl an einer ordnungsgemäßen und betriebswirtschaftlichen Geschäftsführung als auch an Sicherheitsmaßnahmen zum Schutz unserer Vertragspartner und unseres Geschäftsbetriebs vor Missbrauch, Gefährdung ihrer Daten, Geheimnisse, Informationen und Rechte (z. B. zur Beteiligung von Telekommunikations-, Transport- und sonstigen Hilfsdiensten sowie Subunternehmern, Banken, Steuer- und Rechtsberatern, Zahlungsdienstleistern oder Finanzbehörden). Im Rahmen des geltenden Rechts geben wir die Daten von Vertragspartnern nur insoweit an Dritte weiter, als dies für die vorgenannten Zwecke oder zur Erfüllung gesetzlicher Pflichten erforderlich ist. Über weitere Formen der Verarbeitung, etwa zu Marketingzwecken, werden die Vertragspartner im Rahmen dieser Datenschutzerklärung informiert.<br>\\r\n<br>\\r\nWelche Daten für die vorgenannten Zwecke erforderlich sind, teilen wir den Vertragspartnern vor oder im Rahmen der Datenerhebung, z. B. in Onlineformularen, durch besondere Kennzeichnung (z. B. Farben) bzw. Symbole (z. B. Sternchen o. Ä.), oder persönlich mit.<br>\\r\n<br>\\r\nWir löschen die Daten nach Ablauf gesetzlicher Gewährleistungs- und vergleichbarer Pflichten, d. h. grundsätzlich nach vier Jahren, es sei denn, dass die Daten in einem Kundenkonto gespeichert werden, z. B., solange sie aus gesetzlichen Gründen der Archivierung aufbewahrt werden müssen (etwa für Steuerzwecke im Regelfall zehn Jahre). Daten, die uns im Rahmen eines Auftrags durch den Vertragspartner offengelegt wurden, löschen wir entsprechend den Vorgaben und grundsätzlich nach Ende des Auftrags.\\r\n<ul>\\r\n    <li>Verarbeitete Datenarten: Bestandsdaten (z. B. der vollständige Name, Wohnadresse, Kontaktinformationen, Kundennummer, etc.); Zahlungsdaten (z. B. Bankverbindungen, Rechnungen, Zahlungshistorie); Kontaktdaten (z. B. Post- und E-Mail-Adressen oder Telefonnummern). Vertragsdaten (z. B. Vertragsgegenstand, Laufzeit, Kundenkategorie).</li>\\r\n    <li>Betroffene Personen: Leistungsempfänger und Auftraggeber; Interessenten. Geschäfts- und Vertragspartner.</li>\\r\n    <li>Zwecke der Verarbeitung: Erbringung vertraglicher Leistungen und Erfüllung vertraglicher Pflichten; Kommunikation; Büro- und Organisationsverfahren; Organisations- und Verwaltungsverfahren. Geschäftsprozesse und betriebswirtschaftliche Verfahren.</li>\\r\n    <li>Aufbewahrung und Löschung: Löschung entsprechend Angaben im Abschnitt \\\"Allgemeine Informationen zur Datenspeicherung und Löschung\\\".</li>\\r\n    <li>Rechtsgrundlagen: Vertragserfüllung und vorvertragliche Anfragen (Art. 6 Abs. 1 S. 1 lit. b) DSGVO); Rechtliche Verpflichtung (Art. 6 Abs. 1 S. 1 lit. c) DSGVO). Berechtigte Interessen (Art. 6 Abs. 1 S. 1 lit. f) DSGVO).</li>\\r\n</ul>\\r\n<br>\\r\n<b>Weitere Hinweise zu Verarbeitungsprozessen, Verfahren und Diensten:</b>\\r\n<ul>\\r\n    <li>Handwerkliche Leistungen: Wir verarbeiten die Daten unserer Kunden sowie Auftraggeber (nachfolgend einheitlich als \\\"Kunden\\\" bezeichnet), um ihnen die Auswahl, den Erwerb bzw. die Beauftragung der gewählten Leistungen oder Werke sowie verbundener Tätigkeiten als auch deren Bezahlung und Zustellung bzw. Ausführung oder Erbringung zu ermöglichen.</li>\\r\n    <li>Die erforderlichen Angaben sind als solche im Rahmen des Auftrags-, Bestell- bzw. vergleichbaren Vertragsschlusses gekennzeichnet und umfassen die zur Auslieferung und Abrechnung benötigten Angaben sowie Kontaktinformationen, um etwaige Rücksprachen halten zu können; Rechtsgrundlagen: Vertragserfüllung und vorvertragliche Anfragen (Art. 6 Abs. 1 S. 1 lit. b) DSGVO).</li>\\r\n</ul>\\r\n<br>\\r\n<b>Bereitstellung des Onlineangebots und Webhosting</b><br>\\r\n<br>\\r\nWir verarbeiten die Daten der Nutzer, um ihnen unsere Online-Dienste zur Verfügung stellen zu können. Zu diesem Zweck verarbeiten wir die IP-Adresse des Nutzers, die notwendig ist, um die Inhalte und Funktionen unserer Online-Dienste an den Browser oder das Endgerät der Nutzer zu übermitteln.\\r\n<ul>\\r\n    <li>Verarbeitete Datenarten: Nutzungsdaten (z. B. Seitenaufrufe und Verweildauer, Klickpfade, Nutzungsintensität und -frequenz, verwendete Gerätetypen und Betriebssysteme, Interaktionen mit Inhalten und Funktionen); Meta-, Kommunikations- und Verfahrensdaten (z. B. IP-Adressen, Zeitangaben, Identifikationsnummern, beteiligte Personen). Protokolldaten (z. B. Logfiles betreffend Logins oder den Abruf von Daten oder Zugriffszeiten.).</li>\\r\n    <li>Betroffene Personen: Nutzer (z. B. Webseitenbesucher, Nutzer von Onlinediensten).</li>\\r\n    <li>Zwecke der Verarbeitung: Bereitstellung unseres Onlineangebotes und Nutzerfreundlichkeit; Informationstechnische Infrastruktur (Betrieb und Bereitstellung von Informationssystemen und technischen Geräten (Computer, Server etc.).). Sicherheitsmaßnahmen.</li>\\r\n    <li>Aufbewahrung und Löschung: Löschung entsprechend Angaben im Abschnitt \\\"Allgemeine Informationen zur Datenspeicherung und Löschung\\\".</li>\\r\n    <li>Rechtsgrundlagen: Berechtigte Interessen (Art. 6 Abs. 1 S. 1 lit. f) DSGVO).</li>\\r\n</ul>\\r\n<br>\\r\n<b>Weitere Hinweise zu Verarbeitungsprozessen, Verfahren und Diensten:</b><br>\\r\n<br>\\r\nErhebung von Zugriffsdaten und Logfiles: Der Zugriff auf unser Onlineangebot wird in Form von sogenannten \\\"Server-Logfiles\\\" protokolliert. Zu den Serverlogfiles können die Adresse und der Name der abgerufenen Webseiten und Dateien, Datum und Uhrzeit des Abrufs, übertragene Datenmengen, Meldung über erfolgreichen Abruf, Browsertyp nebst Version, das Betriebssystem des Nutzers, Referrer URL (die zuvor besuchte Seite) und im Regelfall IP-Adressen und der anfragende Provider gehören. Die Serverlogfiles können zum einen zu Sicherheitszwecken eingesetzt werden, z. B. um eine Überlastung der Server zu vermeiden (insbesondere im Fall von missbräuchlichen Angriffen, sogenannten DDoS-Attacken), und zum anderen, um die Auslastung der Server und ihre Stabilität sicherzustellen; Rechtsgrundlagen: Berechtigte Interessen (Art. 6 Abs. 1 S. 1 lit. f) DSGVO). Löschung von Daten: Logfile-Informationen werden für die Dauer von maximal 30 Tagen gespeichert und danach gelöscht oder anonymisiert. Daten, deren weitere Aufbewahrung zu Beweiszwecken erforderlich ist, sind bis zur endgültigen Klärung des jeweiligen Vorfalls von der Löschung ausgenommen.<br>\\r\n<br>\\r\n<b>Kontakt- und Anfrageverwaltung</b><br>\\r\n<br>\\r\nBei der Kontaktaufnahme mit uns (z. B. per Post, Kontaktformular, E-Mail, Telefon oder via soziale Medien) sowie im Rahmen bestehender Nutzer- und Geschäftsbeziehungen werden die Angaben der anfragenden Personen verarbeitet, soweit dies zur Beantwortung der Kontaktanfragen und etwaiger angefragter Maßnahmen erforderlich ist.\\r\n<ul>\\r\n    <li>Verarbeitete Datenarten: Bestandsdaten (z. B. der vollständige Name, Wohnadresse, Kontaktinformationen, Kundennummer, etc.); Kontaktdaten (z. B. Post- und E-Mail-Adressen oder Telefonnummern); Inhaltsdaten (z. B. textliche oder bildliche Nachrichten und Beiträge sowie die sie betreffenden Informationen, wie z. B. Angaben zur Autorenschaft oder Zeitpunkt der Erstellung); Nutzungsdaten (z. B. Seitenaufrufe und Verweildauer, Klickpfade, Nutzungsintensität und -frequenz, verwendete Gerätetypen und Betriebssysteme, Interaktionen mit Inhalten und Funktionen). Meta-, Kommunikations- und Verfahrensdaten (z. B. IP-Adressen, Zeitangaben, Identifikationsnummern, beteiligte Personen).</li>\\r\n    <li>Betroffene Personen: Kommunikationspartner.</li>\\r\n    <li>Zwecke der Verarbeitung: Kommunikation; Organisations- und Verwaltungsverfahren; Feedback (z. B. Sammeln von Feedback via Online-Formular). Bereitstellung unseres Onlineangebotes und Nutzerfreundlichkeit.</li>\\r\n    <li>Aufbewahrung und Löschung: Löschung entsprechend Angaben im Abschnitt \\\"Allgemeine Informationen zur Datenspeicherung und Löschung\\\".</li>\\r\n    <li>Rechtsgrundlagen: Berechtigte Interessen (Art. 6 Abs. 1 S. 1 lit. f) DSGVO). Vertragserfüllung und vorvertragliche Anfragen (Art. 6 Abs. 1 S. 1 lit. b) DSGVO).</li>\\r\n</ul>\\r\n<br>\\r\n<b>Weitere Hinweise zu Verarbeitungsprozessen, Verfahren und Diensten:</b><br>\\r\n<br>\\r\nKontaktformular: Bei Kontaktaufnahme über unser Kontaktformular, per E-Mail oder anderen Kommunikationswegen, verarbeiten wir die uns übermittelten personenbezogenen Daten zur Beantwortung und Bearbeitung des jeweiligen Anliegens. Dies umfasst in der Regel Angaben wie Name, Kontaktinformationen und gegebenenfalls weitere Informationen, die uns mitgeteilt werden und zur angemessenen Bearbeitung erforderlich sind. Wir nutzen diese Daten ausschließlich für den angegebenen Zweck der Kontaktaufnahme und Kommunikation; Rechtsgrundlagen: Vertragserfüllung und vorvertragliche Anfragen (Art. 6 Abs. 1 S. 1 lit. b) DSGVO), Berechtigte Interessen (Art. 6 Abs. 1 S. 1 lit. f) DSGVO).<br>\\r\n<br>\\r\nErstellt mit kostenlosem Datenschutz-Generator.de von Dr. Thomas Schwenke', 1, '2026-04-07 15:37:22', 'Install');
INSERT INTO `blocks` (`block_id`, `block_title`, `block_content`, `block_enable`, `datetime`, `username`) VALUES
(8, 'Datenschutzerklärung', '<h1>Datenschutz­erklärung</h1>\\r\n<h2>1. Datenschutz auf einen Blick</h2>\\r\n<h3>Allgemeine Hinweise</h3> <p>Die folgenden Hinweise geben einen einfachen Überblick darüber,\\r\nwas mit Ihren personenbezogenen Daten passiert, wenn Sie diese Website besuchen. Personenbezogene Daten sind\\r\nalle Daten, mit denen Sie persönlich identifiziert werden können. Ausführliche Informationen zum\\r\nThema Datenschutz entnehmen Sie unserer unter diesem Text aufgeführten\\r\nDatenschutzerklärung.</p>\\r\n<h3>Datenerfassung auf dieser Website</h3> <h4>Wer ist verantwortlich für die Datenerfassung auf dieser\\r\nWebsite?</h4> <p>Die Datenverarbeitung auf dieser Website erfolgt durch den Websitebetreiber. Dessen\\r\nKontaktdaten können Sie dem Abschnitt „Hinweis zur Verantwortlichen Stelle“ in dieser\\r\nDatenschutzerklärung entnehmen.</p> <h4>Wie erfassen wir Ihre Daten?</h4> <p>Ihre Daten werden zum\\r\neinen dadurch erhoben, dass Sie uns diese mitteilen. Hierbei kann es sich z.&nbsp;B. um Daten handeln, die Sie in ein\\r\nKontaktformular eingeben.</p> <p>Andere Daten werden automatisch oder nach Ihrer Einwilligung beim Besuch\\r\nder Website durch unsere IT-Systeme erfasst. Das sind vor allem technische Daten (z.&nbsp;B. Internetbrowser,\\r\nBetriebssystem oder Uhrzeit des Seitenaufrufs). Die Erfassung dieser Daten erfolgt automatisch, sobald Sie diese\\r\nWebsite betreten.</p> <h4>Wofür nutzen wir Ihre Daten?</h4> <p>Ein Teil der Daten wird erhoben, um eine\\r\nfehlerfreie Bereitstellung der Website zu gewährleisten. Andere Daten können zur Analyse Ihres\\r\nNutzerverhaltens verwendet werden.</p> <h4>Welche Rechte haben Sie bezüglich Ihrer Daten?</h4>\\r\n<p>Sie haben jederzeit das Recht, unentgeltlich Auskunft über Herkunft, Empfänger und Zweck Ihrer\\r\ngespeicherten personenbezogenen Daten zu erhalten. Sie haben außerdem ein Recht, die Berichtigung oder\\r\nLöschung dieser Daten zu verlangen. Wenn Sie eine Einwilligung zur Datenverarbeitung erteilt haben,\\r\nkönnen Sie diese Einwilligung jederzeit für die Zukunft widerrufen. Außerdem haben Sie das Recht,\\r\nunter bestimmten Umständen die Einschränkung der Verarbeitung Ihrer personenbezogenen Daten zu\\r\nverlangen. Des Weiteren steht Ihnen ein Beschwerderecht bei der zuständigen Aufsichtsbehörde\\r\nzu.</p> <p>Hierzu sowie zu weiteren Fragen zum Thema Datenschutz können Sie sich jederzeit an uns\\r\nwenden.</p>\\r\n<h2>2. Allgemeine Hinweise und Pflicht­informationen</h2>\\r\n<h3>Datenschutz</h3> <p>Die Betreiber dieser Seiten nehmen den Schutz Ihrer persönlichen Daten sehr\\r\nernst. Wir behandeln Ihre personenbezogenen Daten vertraulich und entsprechend den gesetzlichen\\r\nDatenschutzvorschriften sowie dieser Datenschutzerklärung.</p> <p>Wenn Sie diese Website benutzen,\\r\nwerden verschiedene personenbezogene Daten erhoben. Personenbezogene Daten sind Daten, mit denen Sie\\r\npersönlich identifiziert werden können. Die vorliegende Datenschutzerklärung erläutert,\\r\nwelche Daten wir erheben und wofür wir sie nutzen. Sie erläutert auch, wie und zu welchem Zweck das\\r\ngeschieht.</p> <p>Wir weisen darauf hin, dass die Datenübertragung im Internet (z.&nbsp;B. bei der\\r\nKommunikation per E-Mail) Sicherheitslücken aufweisen kann. Ein lückenloser Schutz der Daten vor\\r\ndem Zugriff durch Dritte ist nicht möglich.</p>\\r\n<h3>Hinweis zur verantwortlichen Stelle</h3> <p>Die verantwortliche Stelle für die Datenverarbeitung auf\\r\ndieser Website ist:</p> <p>Geith Steinbildhauer und Steinmetz<br>\\r\nGorbitzer Straße 11<br>\\r\n01157 Dresden</p>\\r\n<p>Telefon: +(49)351 4 24 15 50<br>\\r\nE-Mail: geith.steinrestaurierung@googlemail.com</p>\\r\n <p>Verantwortliche Stelle ist die natürliche oder juristische Person, die allein oder gemeinsam mit anderen\\r\nüber die Zwecke und Mittel der Verarbeitung von personenbezogenen Daten (z.&nbsp;B. Namen, E-Mail-\\r\nAdressen o. Ä.) entscheidet.</p>\\r\n<h3>Speicherdauer</h3> <p>Soweit innerhalb dieser Datenschutzerklärung keine speziellere Speicherdauer\\r\ngenannt wurde, verbleiben Ihre personenbezogenen Daten bei uns, bis der Zweck für die Datenverarbeitung\\r\nentfällt. Wenn Sie ein berechtigtes Löschersuchen geltend machen oder eine Einwilligung zur\\r\nDatenverarbeitung widerrufen, werden Ihre Daten gelöscht, sofern wir keine anderen rechtlich\\r\nzulässigen Gründe für die Speicherung Ihrer personenbezogenen Daten haben (z.&nbsp;B. steuer-\\r\noder handelsrechtliche Aufbewahrungsfristen); im letztgenannten Fall erfolgt die Löschung nach Fortfall\\r\ndieser Gründe.</p>\\r\n<h3>Allgemeine Hinweise zu den Rechtsgrundlagen der Datenverarbeitung auf dieser Website</h3> <p>Sofern Sie\\r\nin die Datenverarbeitung eingewilligt haben, verarbeiten wir Ihre personenbezogenen Daten auf Grundlage von Art.\\r\n6 Abs. 1 lit. a DSGVO bzw. Art. 9 Abs. 2 lit. a DSGVO, sofern besondere Datenkategorien nach Art. 9 Abs. 1 DSGVO\\r\nverarbeitet werden. Im Falle einer ausdrücklichen Einwilligung in die Übertragung personenbezogener\\r\nDaten in Drittstaaten erfolgt die Datenverarbeitung außerdem auf Grundlage von Art. 49 Abs. 1 lit. a DSGVO.\\r\nSofern Sie in die Speicherung von Cookies oder in den Zugriff auf Informationen in Ihr Endgerät (z.&nbsp;B. via\\r\nDevice-Fingerprinting) eingewilligt haben, erfolgt die Datenverarbeitung zusätzlich auf Grundlage von §\\r\n25 Abs. 1 TDDDG. Die Einwilligung ist jederzeit widerrufbar. Sind Ihre Daten zur Vertragserfüllung oder zur\\r\nDurchführung vorvertraglicher Maßnahmen erforderlich, verarbeiten wir Ihre Daten auf Grundlage des\\r\nArt. 6 Abs. 1 lit. b DSGVO. Des Weiteren verarbeiten wir Ihre Daten, sofern diese zur Erfüllung einer\\r\nrechtlichen Verpflichtung erforderlich sind auf Grundlage von Art. 6 Abs. 1 lit. c DSGVO. Die Datenverarbeitung\\r\nkann ferner auf Grundlage unseres berechtigten Interesses nach Art. 6 Abs. 1 lit. f DSGVO erfolgen. Über die\\r\njeweils im Einzelfall einschlägigen Rechtsgrundlagen wird in den folgenden Absätzen dieser\\r\nDatenschutzerklärung informiert.</p>\\r\n<h3>Empfänger von personenbezogenen Daten</h3> <p>Im Rahmen unserer Geschäftstätigkeit\\r\narbeiten wir mit verschiedenen externen Stellen zusammen. Dabei ist teilweise auch eine Übermittlung von\\r\npersonenbezogenen Daten an diese externen Stellen erforderlich. Wir geben personenbezogene Daten nur dann an\\r\nexterne Stellen weiter, wenn dies im Rahmen einer Vertragserfüllung erforderlich ist, wenn wir gesetzlich\\r\nhierzu verpflichtet sind (z.&nbsp;B. Weitergabe von Daten an Steuerbehörden), wenn wir ein berechtigtes\\r\nInteresse nach Art. 6 Abs. 1 lit. f DSGVO an der Weitergabe haben oder wenn eine sonstige Rechtsgrundlage die\\r\nDatenweitergabe erlaubt. Beim Einsatz von Auftragsverarbeitern geben wir personenbezogene Daten unserer\\r\nKunden nur auf Grundlage eines gültigen Vertrags über Auftragsverarbeitung weiter. Im Falle einer\\r\ngemeinsamen Verarbeitung wird ein Vertrag über gemeinsame Verarbeitung geschlossen.</p>\\r\n<h3>Widerruf Ihrer Einwilligung zur Datenverarbeitung</h3> <p>Viele Datenverarbeitungsvorgänge sind\\r\nnur mit Ihrer ausdrücklichen Einwilligung möglich. Sie können eine bereits erteilte Einwilligung\\r\njederzeit widerrufen. Die Rechtmäßigkeit der bis zum Widerruf erfolgten Datenverarbeitung bleibt vom\\r\nWiderruf unberührt.</p>\\r\n<h3>Widerspruchsrecht gegen die Datenerhebung in besonderen Fällen sowie gegen Direktwerbung (Art. 21\\r\nDSGVO)</h3><!--[if gte mso 9]>\\r\n <o:OfficeDocumentSettings>\\r\n  <o:AllowPNG/>\\r\n </o:OfficeDocumentSettings>\\r\n<![endif]--><!--[if gte mso 9]>\\r\n <w:WordDocument>\\r\n  <w:View>Normal</w:View>\\r\n  <w:Zoom>0</w:Zoom>\\r\n  <w:TrackMoves/>\\r\n  <w:TrackFormatting/>\\r\n  <w:HyphenationZone>21</w:HyphenationZone>\\r\n  <w:PunctuationKerning/>\\r\n  <w:ValidateAgainstSchemas/>\\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\\r\n  <w:IgnoreMixedContent>false</w:IgnoreMixedContent>\\r\n  <w:AlwaysShowPlaceholderText>false</w:AlwaysShowPlaceholder